// rt-search-companies — Apollo /v1/mixed_companies/search, output exact
// conform het search_companies v1.0.0 output_schema uit rt_skill_versions.
// De Apollo Master API key komt uit de n8n-omgeving (Settings > Variables of
// een env var op de instance) — NOOIT uit de inkomende payload; de executor
// stuurt alleen een credential_reference mee die hier genegeerd wordt.
const APOLLO_API_KEY = $env.APOLLO_API_KEY || '<APOLLO_API_KEY>';

const body = $input.first().json.body || $input.first().json;
const input = body.input || {};

if (!input.country) {
  return [{ json: { error: { code: 'input_invalid', message: 'country is verplicht', retryable: false } } }];
}
const targetCount = Math.min(Math.max(parseInt(input.target_count, 10) || 100, 1), 1000);

const searchBody = {
  q_organization_locations: [input.country],
  per_page: 100,
};
if (Array.isArray(input.industries) && input.industries.length > 0) {
  searchBody.q_organization_keyword_tags = input.industries;
}
if (input.employee_min || input.employee_max) {
  searchBody.organization_num_employees_ranges = [
    `${input.employee_min || 1},${input.employee_max || 100000}`,
  ];
}

try {
  const all = [];
  let page = 1;
  let totalPages = 1;
  do {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.apollo.io/v1/mixed_companies/search',
      headers: {
        'X-Api-Key': APOLLO_API_KEY,
        'Content-Type': 'application/json',
        'Cache-Control': 'no-cache',
      },
      body: { ...searchBody, page },
      json: true,
    });
    const orgs = response.organizations || response.accounts || [];
    all.push(...orgs);
    totalPages = response.pagination?.total_pages || 1;
    page++;
    if (page > 20) break; // hard cap tegen runaway loops
  } while (page <= totalPages && all.length < targetCount);

  const accounts = all.slice(0, targetCount).filter((o) => o.name).map((o) => {
    let domain = o.primary_domain || o.domain || '';
    if (!domain && o.website_url) {
      domain = o.website_url.replace(/^https?:\/\/(www\.)?/, '').replace(/\/.*$/, '');
    }
    return {
      name: o.name,
      domain: domain.toLowerCase().trim(),
      industry: o.industry || '',
      country: o.country || input.country,
      employee_range: o.estimated_num_employees ? String(o.estimated_num_employees) : '',
      source_provider: 'apollo',
      external_ids: { apollo_organization_id: o.id },
    };
  });

  return [{ json: { accounts } }];
} catch (e) {
  const msg = String(e.message || e);
  const retryable = msg.includes('429') || msg.includes('50');
  return [{ json: { error: { code: 'apollo_error', message: msg.slice(0, 200), retryable } } }];
}
